{
  "family": "Hofmann-L\u00f6ffler-Freytag Reaction (Remote Functionalization)",
  "candidate": {
    "substrate_smiles": [
      "CCCCN(C)Cl"
    ],
    "product_smiles": [
      "C1CCCN1C"
    ],
    "optional_reagent_smiles": [
      "O.O=S(=O)(O)O"
    ],
    "rationale": "This is a classic and simple example of the Hofmann-L\u00f6ffler-Freytag reaction. The substrate, N-chloro-N-methylbutan-1-amine, undergoes a 1,5-hydrogen atom transfer upon treatment with acid (e.g., sulfuric acid) and light/heat, leading to a carbon radical at the delta-position. This radical then abstracts the chlorine atom, and subsequent intramolecular nucleophilic substitution by the nitrogen atom upon basification yields the characteristic pyrrolidine product, N-methylpyrrolidine. The acyclic substrate and simple alkyl groups make it a clear, canonical representation of the remote C-H functionalization to form a five-membered ring.",
    "collision_avoidance_note": "This example uses a simple acyclic N-chloroamine substrate, which is the defining feature of the reaction. It avoids arenes (present in some Hofmann-Martius rearrangements), complex ring systems, or other functional groups that could cause collisions with unrelated radical reactions or rearrangements. The transformation is a specific intramolecular C-H amination via a nitrogen-centered radical, distinguishing it from other named reactions involving amines or radicals."
  }
}
